class Solution:
    def largestVariance(self, s):
        from collections import Counter
        n = len(s)
        best = 0
        for i in range(n):
            cnt = Counter()
            for j in range(i, n):
                cnt[s[j]] += 1
                hi = max(cnt.values())
                lo = min(cnt[c] for c in cnt)
                if len(cnt) >= 2:
                    if hi - lo > best:
                        best = hi - lo
        return best

