var largestVariance = function(s) {
    const letters = new Set(s);
    let best = 0;
    for (const a of letters) {
        for (const b of letters) {
            if (a === b) continue;
            let countA = 0, countB = 0, seenB = false;
            for (const ch of s) {
                if (ch === a) countA++;
                else if (ch === b) { countB++; seenB = true; }
                if (seenB && countA - countB > best) best = countA - countB;
                if (countA < countB) { countA = 0; countB = 0; seenB = false; }
            }
        }
    }
    return best;
};
